  button: { backgroundColor: "#007bff", color: "white", border: "none", borderRadius: 8, padding: "10px 20px", fontSize: 16, cursor: "pointer" },
  input: { fontSize: 16, padding: "5px 10px", borderRadius: 4, border: "1px solid #ccc" },
  qaContainer: { fontFamily: "Arial, sans-serif", maxWidth: 500, margin: "20px auto", padding: 20, border: "2px solid #333", borderRadius: 12, backgroundColor: "#fff", textAlign: "left" },
  questionBox: { marginTop: 10, padding: 10, border: "1px solid #333", borderRadius: 6, backgroundColor: "#f9f9f9" },
  answer: { color: "green", fontWeight: "bold", marginTop: 10 },
  acceptButton: { backgroundColor: "#28a745", color: "#fff", border: "none", borderRadius: 6, padding: "8px 12px", cursor: "pointer", fontWeight: "bold" },
  inputRow: { display: "flex", justifyContent: "center", gap: 10, marginBottom: 20 },
};

export default App;
